import functions_framework
import hashlib
import hmac
import json
import os
from typing import Dict, Any

WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET', 'your-secret-key-here')

def verify_signature(payload: bytes, signature: str, secret: str) -> bool:
    """Verify webhook signature using HMAC SHA256"""
    if not signature:
        return False
    
    expected_signature = hmac.new(
        secret.encode('utf-8'),
        payload,
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(signature, expected_signature)

def validate_payment_webhook(data: Dict[str, Any]) -> bool:
    """Validate payment webhook data structure"""
    required_fields = ['event_type', 'transaction_id', 'amount', 'timestamp']
    return all(field in data for field in required_fields)

def process_payment_event(event_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process different types of payment events"""
    event_type = event_data.get('event_type')
    transaction_id = event_data.get('transaction_id')
    
    if event_type == 'payment.completed':
        return {
            'status': 'success',
            'message': f'Payment {transaction_id} processed successfully',
            'transaction_id': transaction_id
        }
    elif event_type == 'payment.failed':
        return {
            'status': 'acknowledged',
            'message': f'Payment {transaction_id} failure recorded',
            'transaction_id': transaction_id
        }
    elif event_type == 'payment.refunded':
        return {
            'status': 'acknowledged',
            'message': f'Refund for {transaction_id} processed',
            'transaction_id': transaction_id
        }
    else:
        return {
            'status': 'acknowledged',
            'message': f'Event {event_type} received',
            'transaction_id': transaction_id
        }

@functions_framework.http
def webhook_handler(request):
    """HTTP Cloud Function for processing payment webhooks"""
    
    if request.method != 'POST':
        return {'error': 'Method not allowed'}, 405
    
    signature = request.headers.get('X-Webhook-Signature', '')
    content_type = request.headers.get('Content-Type', '')
    
    if 'application/json' not in content_type:
        return {'error': 'Content-Type must be application/json'}, 400
    
